const savedMessage = $input.first().json;
const replyContext = $('Build API Response').item.json;
let routeContext = { messages: [] };
try {
  routeContext = $('Expose Route Metadata').item.json;
} catch (error) {
  routeContext = { messages: [] };
}
const messages = Array.isArray(routeContext.messages) ? routeContext.messages : [];
const lastUserFromRoute = [...messages].reverse().find((m) => m.role === 'user');
const latestUserMessage = (lastUserFromRoute?.content || $('Normalize Input').item.json.message || '').trim();

const { shouldExtractMemory, buildExtractionPrompt } = require('/opt/ghost/src/runtime/memory.ts');

const ctx = {
  conversation_id: replyContext.conversation_id || null,
  source_message_id: savedMessage.id || null,
  task_class: replyContext.task_class || 'chat',
  assistant_reply: (replyContext.reply || '').trim(),
  latest_user_message: latestUserMessage,
  command_success: replyContext.command_success ?? null,
  response_mode: replyContext.response_mode || 'direct_owner_reply',
  approval_required: !!replyContext.approval_required,
  error_type: replyContext.error_type || '',
  memory_test_mode: $('Normalize Input').item.json.memory_test_mode || '',
  provider_used: replyContext.provider_used || '',
  model_used: replyContext.model_used || '',
  risk_level: replyContext.risk_level || 'safe',
};

const { should_extract, meaningful_technical_work, explicit_memory_cue } = shouldExtractMemory(ctx);
const extractionPrompt = should_extract ? buildExtractionPrompt(ctx) : '';

return [{ json: {
  ...ctx,
  should_extract_memory: should_extract,
  meaningful_technical_work,
  explicit_memory_cue,
  extraction_prompt: extractionPrompt,
  memory_debug: {
    extractor_attempted: should_extract,
    extractor_skipped: !should_extract,
    fallback_used: false,
    candidate_count: 0,
    filtered_count: 0,
    saved_count: 0,
  },
} }];

const response = $input.first().json;
const ctx = $('Build Memory Extraction Input').item.json;

const { parseMemoryCandidates } = require('/opt/ghost/src/runtime/memory.ts');

const { candidates, parse_status, parse_error, fallback_used, raw_text } =
  parseMemoryCandidates(response, ctx);

return [{ json: {
  ...ctx,
  memory_parse_status: parse_status,
  memory_parse_error: parse_error,
  memory_raw_text: raw_text,
  memory_candidate_items: candidates,
  memory_debug: {
    ...(ctx.memory_debug || {}),
    extractor_attempted: Boolean(ctx.should_extract_memory),
    extractor_skipped: !ctx.should_extract_memory,
    candidate_count: candidates.length,
    fallback_used,
    parse_status,
  },
} }];

const item = $input.first().json;
const candidates = Array.isArray(item.memory_candidate_items) ? item.memory_candidate_items : [];

const { consolidateMemories, buildMemoryWriteRows } = require('/opt/ghost/src/runtime/memory.ts');

const { memories, filtered_out_count, filtered_out_reasons, normalization_changes } =
  consolidateMemories(candidates, item);

const writeRows = buildMemoryWriteRows(memories, item);

return [{ json: {
  ...item,
  memory_items: memories,
  memory_write_rows: writeRows,
  memory_debug: {
    ...(item.memory_debug || {}),
    candidate_count: candidates.length,
    filtered_count: memories.length,
    filtered_out_count,
    filtered_out_reasons,
    normalization_changes,
  },
} }];

const rows = $input.all().map((entry) => entry.json || {});
const context = $('Filter Structured Memory Candidates').item.json;
const savedRows = rows.filter((row) => !row.error && row.id);
const supersededCount = savedRows.length ? Number(savedRows[0].superseded_count || 0) : 0;
return [{ json: {
  conversation_id: context.conversation_id || '',
  source_message_id: context.source_message_id || '',
  memory_debug: {
    ...(context.memory_debug || {}),
    saved_count: savedRows.length,
    superseded_count: supersededCount,
    saved_items: savedRows.map((row) => ({
      id: row.id,
      scope: row.scope,
      memory_type: row.memory_type,
      summary: row.summary,
    })),
  },
} }];
